mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT B.BOARD_ID AS boardId, B.MEMBER_ID AS memberId, B.BOARD_TYPE AS boardType, B.TITLE AS title, B.CONTENT AS content, B.VIEW_COUNT AS viewCount, B.LIKE_COUNT AS likeCount, TO_CHAR(B.CREATE_DATE, 'YYYY-MM-DD') AS createDate, B.IS_HIDDEN AS isHidden, M.PROFILE_IMG AS profileImg, M.ROLE AS role FROM BOARD B LEFT JOIN MEMBER M ON B.MEMBER_ID = M.MEMBER_ID WHERE 1=1 AND (B.IS_HIDDEN IS NULL OR B.IS_HIDDEN = 'N')
AND B.BOARD_TYPE = #{boardType}
AND B.TITLE LIKE '%' || #{keyword} || '%'
ORDER BY B.BOARD_ID DESC ) T WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

SELECT COUNT(*) FROM BOARD WHERE 1=1 AND (IS_HIDDEN IS NULL OR IS_HIDDEN = 'N')
AND BOARD_TYPE = #{boardType}
AND TITLE LIKE '%' || #{keyword} || '%'

SELECT COUNT(*)
FROM BOARD_LIKE
WHERE BOARD_ID = #{boardId}
AND MEMBER_ID
= #{memberId}

